static create(
	manifestData: RoutesList,
	{
		loader,
		logger,
		manifest,
		settings,
		getDebugInfo,
	}: Pick<RunnablePipeline, 'loader' | 'logger' | 'manifest' | 'settings' | 'getDebugInfo'>,
) {
	const pipeline = new RunnablePipeline(loader, logger, manifest, settings, getDebugInfo);
	pipeline.routesList = manifestData;
	if (queueRenderingEnabled(manifest.experimentalQueuedRendering)) {
		pipeline.nodePool = newNodePool(manifest.experimentalQueuedRendering!);
		if (manifest.experimentalQueuedRendering!.contentCache) {
			pipeline.htmlStringCache = new HTMLStringCache(1000);
		}
	}
	return pipeline;
}

async tryRewrite(payload: RewritePayload, request: Request): Promise<TryRewriteResult> {
	if (!this.routesList) {
		throw new Error('Missing manifest data. This is an internal error, please file an issue.');
	}
	const { routeData, pathname, newUrl } = findRouteToRewrite({
		payload,
		request,
		routes: this.routesList?.routes,
		trailingSlash: this.manifest.trailingSlash,
		buildFormat: this.manifest.buildFormat,
		base: this.manifest.base,
		outDir: this.manifest.outDir,
	});

	const componentInstance = await this.getComponentByRoute(routeData);
	return { newUrl, pathname, componentInstance, routeData };
}

export function normalizeFilename(filename: string, root: URL) {
	if (filename.startsWith('/@fs')) {
		filename = filename.slice('/@fs'.length);
	} else if (filename.startsWith('.')) {
		// Handle relative paths (e.g. ./src/components/Foo.astro) by resolving against root.
		// This can occur on certain environments (e.g. Windows + newer Node.js) when a component
		// is imported via a TypeScript path alias and Vite produces a relative virtual module ID.
		const url = new URL(filename, root);
		filename = viteID(url);
	} else if (filename.startsWith('/') && !isPathInRoot(filename, fileURLToPath(root))) {
		const url = new URL('.' + filename, root);
		filename = viteID(url);
	}
	return removeLeadingForwardSlashWindows(filename);
}

export async function cf(
	state: FetchState,
	env: Env,
	ctx: ExecutionContext,
): Promise<Response | undefined> {
	ensureInitialized();
	injectSessionBinding(app!.manifest, env);

	const staticAsset = matchStaticAsset(app!.manifest, state.request.url, env);
	if (staticAsset) return staticAsset;

	if (!state.routeData) {
		const asset = await fallbackToAssets(state.request.url, env);
		if (asset) return asset;
	}

	Object.assign(state.locals, createLocals(ctx));
	state.clientAddress = getClientAddress(state.request);
	state.renderOptions.waitUntil = ctx.waitUntil.bind(ctx);
	state.renderOptions.prerenderedErrorPageFetch = createErrorPageFetch(env);

	return undefined;
}

export function recordServerError(
	loader: ModuleLoader,
	manifest: SSRManifest,
	logger: AstroLogger,
	err: Error,
) {
	// This could be a runtime error from Vite's SSR module, so try to fix it here
	try {
		loader.fixStacktrace(err);
	} catch {}

	// This is our last line of defense regarding errors where we still might have some information about the request
	// Our error should already be complete, but let's try to add a bit more through some guesswork
	const errorWithMetadata = collectErrorMetadata(err, manifest.rootDir);

	logger.error(null, formatErrorMessage(errorWithMetadata, logger.level() === 'debug'));

	return {
		errorWithMetadata,
	};
}

async ({ params, request, locals }) => {
	const { emdash, user } = locals;
	const denied = requirePerm(user, "schema:manage");
	if (denied) return denied;

	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;

	const slug = params.slug;
	if (!slug) return apiError("MISSING_PARAM", "Field slug is required", 400);

	const body = await parseBody(request, bylineFieldUpdateBody);
	if (isParseError(body)) return body;

	const result = await handleBylineFieldUpdate(emdash.db, slug, {
		label: body.label,
		required: body.required,
		translatable: body.translatable,
		// `null` clears the stored validation; `undefined` leaves it as-is.
		// The zod schema makes `validation` itself optional, so an absent
		// key reaches the handler as `undefined`.
		validation: body.validation,
		sortOrder: body.sortOrder,
	});
	return unwrapResult(result);
}

async ({ request, locals }) => {
	const { emdash, user } = locals;
	const denied = requirePerm(user, "schema:manage");
	if (denied) return denied;

	const dbErr = requireDb(emdash?.db);
	if (dbErr) return dbErr;

	const body = await parseBody(request, bylineFieldCreateBody);
	if (isParseError(body)) return body;

	const result = await handleBylineFieldCreate(emdash.db, {
		slug: body.slug,
		label: body.label,
		type: body.type,
		required: body.required,
		translatable: body.translatable,
		validation: body.validation ?? null,
		sortOrder: body.sortOrder,
	});
	return unwrapResult(result, 201);
}

async ({ params, locals, cache }) => {
	const { emdash, user } = locals;
	const collection = params.collection!;
	const id = params.id!;

	const denied = requirePerm(user, "content:delete_permanent");
	if (denied) return denied;

	if (!emdash?.handleContentPermanentDelete) {
		return apiError("NOT_CONFIGURED", "EmDash is not initialized", 500);
	}

	const result = await emdash.handleContentPermanentDelete(collection, id);

	if (!result.success) return unwrapResult(result);

	if (cache?.enabled) await cache.invalidate({ tags: [collection, id] });

	return unwrapResult(result);
}

export async function getEntrySlug({
	id,
	collection,
	generatedSlug,
	contentEntryType,
	fileUrl,
	fs,
}: {
	fs: typeof fsMod;
	id: string;
	collection: string;
	generatedSlug: string;
	fileUrl: URL;
	contentEntryType: Pick<ContentEntryType, 'getEntryInfo'>;
}) {
	let contents: string;
	try {
		contents = await fs.promises.readFile(fileUrl, 'utf-8');
	} catch (e) {
		// File contents should exist. Raise unexpected error as "unknown" if not.
		throw new AstroError(AstroErrorData.UnknownContentCollectionError, { cause: e });
	}
	const { slug: frontmatterSlug } = await contentEntryType.getEntryInfo({
		fileUrl,
		contents,
	});
	return parseEntrySlug({ generatedSlug, frontmatterSlug, id, collection });
}

async getMiddleware(): Promise<MiddlewareHandler> {
	if (this.resolvedMiddleware) {
		return this.resolvedMiddleware;
	}
	// The middleware can be undefined when using edge middleware.
	// This is set to undefined by the plugin-ssr.ts
	if (this.middleware) {
		const middlewareInstance = await this.middleware();
		const onRequest = middlewareInstance.onRequest ?? NOOP_MIDDLEWARE_FN;
		const internalMiddlewares = [onRequest];
		if (this.manifest.checkOrigin) {
			// this middleware must be placed at the beginning because it needs to block incoming requests
			internalMiddlewares.unshift(createOriginCheckMiddleware());
		}
		this.resolvedMiddleware = sequence(...internalMiddlewares);
		return this.resolvedMiddleware;
	} else {
		this.resolvedMiddleware = NOOP_MIDDLEWARE_FN;
		return this.resolvedMiddleware;
	}
}

export async function createSettings(
	config: AstroConfig,
	logLevel: AstroInlineConfig['logLevel'],
	cwd?: string,
): Promise<AstroSettings> {
	const tsconfig = await loadTSConfig(cwd);
	const settings = createBaseSettings(config, logLevel);

	let watchFiles = [];
	if (cwd) {
		watchFiles.push(fileURLToPath(new URL('./package.json', pathToFileURL(cwd))));
	}

	if (!tsconfig.error) {
		watchFiles.push(...tsconfig.sources);
		settings.tsConfig = tsconfig.tsconfig;
		settings.tsConfigPath = tsconfig.tsconfigFile;
	}

	settings.watchFiles = watchFiles;

	return settings;
}

getClientAddress(): string {
	const { pipeline, clientAddress } = this;
	const routeData = this.routeData!;

	if (routeData.prerender) {
		throw new AstroError({
			...AstroErrorData.PrerenderClientAddressNotAvailable,
			message: AstroErrorData.PrerenderClientAddressNotAvailable.message(routeData.component),
		});
	}

	if (clientAddress) {
		return clientAddress;
	}

	if (pipeline.adapterName) {
		throw new AstroError({
			...AstroErrorData.ClientAddressNotAvailable,
			message: AstroErrorData.ClientAddressNotAvailable.message(pipeline.adapterName),
		});
	}

	throw new AstroError(AstroErrorData.StaticClientAddressNotAvailable);
}

async #getLoaderContext({
	collectionName,
	loaderName = 'content',
	parseData,
	refreshContextData,
}: {
	collectionName: string;
	loaderName: string;
	parseData: LoaderContext['parseData'];
	refreshContextData?: Record<string, unknown>;
}): Promise<LoaderContext> {
	return {
		collection: collectionName,
		store: this.#store.scopedStore(collectionName),
		meta: this.#store.metaStore(collectionName),
		logger: this.#logger.forkIntegrationLogger(loaderName),
		config: this.#settings.config,
		parseData,
		renderMarkdown: this.#processMarkdown.bind(this),
		generateDigest: await this.#getGenerateDigest(),
		watcher: this.#watcher,
		refreshContextData,
		entryTypes: getEntryConfigByExtMap([
			...this.#settings.contentEntryTypes,
			...this.#settings.dataEntryTypes,
		] as Array<ContentEntryType>),
	};
}

constructor(
	result: SSRResult,
	props: ComponentProps,
	slots: ComponentSlots,
	factory: AstroComponentFactory,
) {
	this.result = result;
	this.props = props;
	this.factory = factory;
	this.slotValues = {};
	for (const name in slots) {
		// prerender the slots eagerly to make collection entries propagate styles and scripts
		let didRender = false;
		let value = slots[name](result);
		this.slotValues[name] = () => {
			// use prerendered value only once
			if (!didRender) {
				didRender = true;
				return value;
			}
			// render afresh for the advanced use-case where the same slot is rendered multiple times
			return slots[name](result);
		};
	}
}

constructor(htmlParts: TemplateStringsArray, expressions: unknown[]) {
	this.htmlParts = htmlParts;
	this.error = undefined;
	this.expressions = expressions.map((expression) => {
		// Wrap Promise expressions so we can catch errors
		// There can only be 1 error that we rethrow from an Astro component,
		// so this keeps track of whether or not we have already done so.
		if (isPromise(expression)) {
			return Promise.resolve(expression).catch((err) => {
				if (!this.error) {
					this.error = err;
					throw err;
				}
			});
		}
		return expression;
	});
}

public addServerRenderer(options: AddServerRenderer): void {
	const { renderer } = options;
	if (!renderer.check || !renderer.renderToStaticMarkup) {
		throw new Error(
			"The renderer you passed isn't valid. A renderer is usually an object that exposes the `check` and `renderToStaticMarkup` functions.\n" +
				"Usually, the renderer is exported by a /server.js entrypoint e.g. `import renderer from '@astrojs/react/server.js'`",
		);
	}
	if (isNamedRenderer(renderer)) {
		this.#pipeline.manifest.renderers.push({
			name: renderer.name,
			ssr: renderer,
		});
	} else if ('name' in options) {
		this.#pipeline.manifest.renderers.push({
			name: options.name,
			ssr: renderer,
		});
	} else {
		throw new Error(
			'The renderer name must be provided when adding a server renderer that is not a named renderer.',
		);
	}
}

export function toIntegrationResolvedRoute(
	route: RouteData,
	trailingSlash: AstroConfig['trailingSlash'],
): IntegrationResolvedRoute {
	return {
		isPrerendered: route.prerender,
		entrypoint: route.component,
		pattern: route.route,
		params: route.params,
		origin: route.origin,
		generate: getRouteGenerator(route.segments, trailingSlash),
		patternRegex: route.pattern,
		segments: route.segments,
		type: route.type,
		pathname: route.pathname,
		redirect: route.redirect,
		redirectRoute: route.redirectRoute
			? toIntegrationResolvedRoute(route.redirectRoute, trailingSlash)
			: undefined,
		fallbackRoutes: route.fallbackRoutes.map((fallbackRoute) =>
			toIntegrationResolvedRoute(fallbackRoute, trailingSlash),
		),
	};
}
